//! Schema parity against fixtures generated by Python lerobot itself
//! (tests/fixtures/golden, regenerated via `pixi run dump-golden` in
//! compliance/). Field names, order, and types are compared through a
//! pyarrow-style rendering so list-vs-fixed-size-list choices and column
//! layouts stay pinned to ground truth.

use std::num::NonZeroU32;

use arrow::datatypes::{DataType, Schema};
use serde_json::Value;

use crate::config::{CameraSpec, DatasetConfig, SourceEncoding};
use crate::layout::FileSlot;
use crate::meta::episodes::{EpisodeRow, FeatureStatsEntry, VideoLocation, episodes_schema};
use crate::meta::stats::FeatureStats;

fn golden(name: &str) -> Value {
    let path = format!(
        "{}/tests/fixtures/golden/{name}",
        env!("CARGO_MANIFEST_DIR")
    );
    serde_json::from_str(&std::fs::read_to_string(&path).expect("golden fixture present"))
        .expect("valid golden json")
}

/// Renders an arrow type the way pyarrow prints it in the golden dumps.
fn pyarrow_type(data_type: &DataType) -> String {
    match data_type {
        DataType::Float32 => "float".into(),
        DataType::Float64 => "double".into(),
        DataType::Int64 => "int64".into(),
        DataType::Utf8 => "string".into(),
        DataType::FixedSizeList(field, len) => format!(
            "fixed_size_list<{}: {}>[{len}]",
            field.name(),
            pyarrow_type(field.data_type())
        ),
        DataType::List(field) => format!(
            "list<{}: {}>",
            field.name(),
            pyarrow_type(field.data_type())
        ),
        other => panic!("no pyarrow rendering for {other:?}"),
    }
}

fn rendered_fields(schema: &Schema) -> Vec<(String, String)> {
    schema
        .fields()
        .iter()
        .map(|f| (f.name().clone(), pyarrow_type(f.data_type())))
        .collect()
}

fn golden_fields(fixture: &Value) -> Vec<(String, String)> {
    fixture["fields"]
        .as_array()
        .expect("fields array")
        .iter()
        .map(|f| {
            (
                f["name"].as_str().unwrap().to_string(),
                f["type"].as_str().unwrap().to_string(),
            )
        })
        .collect()
}

/// The config the golden dataset was generated with (dump_golden_schemas.py).
fn golden_config() -> DatasetConfig {
    let spec = CameraSpec {
        width: NonZeroU32::new(64).unwrap(),
        height: NonZeroU32::new(48).unwrap(),
        source: SourceEncoding::Rgb8,
    };
    DatasetConfig::builder("synthetic_test", NonZeroU32::new(30).unwrap())
        .state((0..4).map(|i| format!("state_{i}")).collect())
        .action((0..3).map(|i| format!("action_{i}")).collect())
        .camera("observation.images.cam_a", spec)
        .camera("observation.images.cam_b", spec)
        .build()
        .unwrap()
}

#[test]
fn data_schema_matches_golden() {
    let schema = crate::data::data_schema(&golden_config());
    assert_eq!(
        rendered_fields(&schema),
        golden_fields(&golden("schema.data.json"))
    );
}

#[test]
fn episodes_schema_matches_golden() {
    let stats = |dims: usize| FeatureStats {
        min: vec![0.0; dims],
        max: vec![0.0; dims],
        mean: vec![0.0; dims],
        std: vec![0.0; dims],
        count: 1,
        quantiles: std::array::from_fn(|_| vec![0.0; dims]),
    };
    let entry = |key: &str, is_image: bool, dims: usize| FeatureStatsEntry {
        key: key.into(),
        is_image,
        stats: stats(dims),
    };
    let location = VideoLocation {
        slot: FileSlot::default(),
        from_timestamp: 0.0,
        to_timestamp: 1.0,
    };
    let row = EpisodeRow {
        episode_index: 0,
        task: "t".into(),
        length: 1,
        data_slot: FileSlot::default(),
        dataset_from_index: 0,
        dataset_to_index: 1,
        videos: vec![
            ("observation.images.cam_a".into(), location),
            ("observation.images.cam_b".into(), location),
        ],
        stats: vec![
            entry("observation.state", false, 4),
            entry("action", false, 3),
            entry("observation.images.cam_a", true, 3),
            entry("observation.images.cam_b", true, 3),
            entry("timestamp", false, 1),
            entry("frame_index", false, 1),
            entry("episode_index", false, 1),
            entry("index", false, 1),
            entry("task_index", false, 1),
        ],
        episodes_slot: FileSlot::default(),
    };
    assert_eq!(
        rendered_fields(&episodes_schema(&row)),
        golden_fields(&golden("schema.episodes.json"))
    );
}

#[test]
fn tasks_metadata_marks_task_as_pandas_index() {
    let fixture = golden("schema.tasks.json");
    assert_eq!(
        golden_fields(&fixture),
        vec![
            ("task_index".to_string(), "int64".to_string()),
            ("task".to_string(), "string".to_string()),
        ]
    );
    let golden_pandas: Value =
        serde_json::from_str(fixture["metadata"]["pandas"].as_str().unwrap()).unwrap();
    assert_eq!(golden_pandas["index_columns"], serde_json::json!(["task"]));
}

#[test]
fn info_json_matches_golden_shape() {
    let fixture = golden("info.json");
    let info = crate::meta::info::build_info_json(
        &golden_config(),
        &crate::meta::info::Totals {
            episodes: 3,
            frames: 135,
            tasks: 2,
        },
    );
    for key in [
        "codebase_version",
        "fps",
        "total_episodes",
        "total_frames",
        "total_tasks",
        "chunks_size",
        "data_files_size_in_mb",
        "video_files_size_in_mb",
        "data_path",
        "video_path",
        "robot_type",
        "splits",
    ] {
        assert_eq!(info[key], fixture[key], "info.json key {key}");
    }
    let ours: Vec<&String> = info["features"].as_object().unwrap().keys().collect();
    let golden_keys: Vec<&String> = fixture["features"].as_object().unwrap().keys().collect();
    assert_eq!(ours, golden_keys, "feature key order");
    for (key, feature) in fixture["features"].as_object().unwrap() {
        assert_eq!(
            info["features"][key]["dtype"], feature["dtype"],
            "{key} dtype"
        );
        assert_eq!(
            info["features"][key]["shape"], feature["shape"],
            "{key} shape"
        );
        assert_eq!(
            info["features"][key]["names"], feature["names"],
            "{key} names"
        );
    }
}
